#include <stdio.h>
#include <stdlib.h>

int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    double* P = (double*) malloc(N * sizeof(double));
    for (int i = 0; i < N; i++) {
        scanf("%lf", &P[i]);
    }
    for (int i = 0; i < Q; i++) {
        int type, L, R;
        double T;
        scanf("%d %d %d", &type, &L, &R);
        L--;
        R--;
        if (type == 0) {
            double prob = 1.0;
            for (int j = L; j <= R; j++) {
                prob *= (1.0 - P[j]);
            }
            printf("%.6f\n", prob);
        } else {
            scanf("%lf", &T);
            for (int j = L; j <= R; j++) {
                P[j] = P[j] * T;
            }
        }
    }
    free(P);
    return 0;
}

