import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int Q = sc.nextInt();
        double[] P = new double[N];
        for (int i = 0; i < N; i++) {
            P[i] = sc.nextDouble();
        }
        for (int i = 0; i < Q; i++) {
            int type = sc.nextInt();
            int L = sc.nextInt() - 1;
            int R = sc.nextInt() - 1;
            if (type == 0) {
                double prob = 1.0;
                for (int j = L; j <= R; j++) {
                    prob *= (1.0 - P[j]);
                }
                System.out.println(prob);
            } else {
                double T = sc.nextDouble();
                for (int j = L; j <= R; j++) {
                    P[j] = P[j] * T;
                }
            }
        }
    }
}

