const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const [N, Q] = readline().split(' ').map(Number);
const P = readline().split(' ').map(Number);
for (let i = 0; i < Q; i++) {
    const [type, L, R] = readline().split(' ').map(Number);
    const T = type === 0 ? 0 : parseFloat(readline().split(' ')[0]);
    if (type === 0) {
        let prob = 1.0;
        for (let j = L - 1; j < R; j++) {
            prob *= (1.0 - P[j]);
        }
        console.log(prob);
    } else {
        for (let j = L - 1; j < R; j++) {
            P[j] = P[j] * T;
        }
    }
}
